mapper.select:
		/*
             SQL ID : SeminarLogDAO.select
            	 설  명 : 세미나 로그 정보 조회
         */

         AND SEMINAR_LOG_ID = #{seminarLogId}

		/*
             SQL ID : SeminarLogDAO.list
            	 설  명 : 세미나 로그 목록 조회
         */


         	AND SMNR_ID = #{seminarId}


         	AND STD_ID = #{stdNo}

         ORDER BY FRST_INQ_DTTM DESC

mapper.insert:
		/*
             SQL ID : SeminarLogDAO.insert
            	 설  명 : 세미나 로그 등록
         */
         INSERT INTO TB_LMS_SEMINAR_LOG (
         	  SEMINAR_LOG_ID
			, SMNR_ID
			, STD_ID
			, SDTTM
			, EDTTM
			, CNTN_DVC_TYCD
			, ATND_SCNDS
			, ATND_STSCD
			, USER_ID
			, RGTR_IP
			, RGTR_ID
			, FRST_INQ_DTTM
         ) VALUES (
         	  #{seminarLogId}
         	, #{seminarId}
         	, #{stdNo}
         	, #{startDttm}
         	, #{endDttm}
         	, IFNULL(#{deviceTypeCd}, '-')
         	, #{atndTime}
         	, #{atndCd}
         	, #{userId}
         	, IFNULL(#{regIp}, '-')
         	, #{rgtrId}
         	, FN_DTTM()
         )
